// Hard block: If AI output contains save-success semantics on non-save path,
// discard entirely and return fixed system message.
// v5-keywords-only: Only block save-success keywords (removed structured fields - too broad)
const output = $input.first().json.output || '';

// Save-success indicators only
// These words only appear when claiming a save occurred
const saveSuccessPatterns = [
  /\bsaved\b/i,
  /\bcreated\b/i,
  /\bpersisted\b/i
];

const hasSaveSuccess = saveSuccessPatterns.some(p => p.test(output));

if (hasSaveSuccess) {
  return {
    sanitized_output: 'No save was performed. To save something, please use an explicit save command.'
  };
}

return { sanitized_output: output };

// Extract claimed artifact_id and type from AI output
const output = $input.first().json.output || '';

// UUID pattern
const uuidPattern = /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi;
const uuidMatches = output.match(uuidPattern);

// Try to find artifact_id specifically labeled
const artifactIdPattern = /artifact_id:\s*([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i;
const artifactIdMatch = output.match(artifactIdPattern);

// Extract artifact type from output
const typePattern = /artifact_type:\s*(journal|project|snapshot|restart|instruction_pack)/i;
const typeMatch = output.match(typePattern);

// Also check for type in save confirmation
const savedTypePattern = /✓\s*Saved\s+(journal|project|snapshot|restart|instruction_pack)/i;
const savedTypeMatch = output.match(savedTypePattern);

// Infer type from original message if not in output
const originalMsg = $('Telegram_Trigger').item.json.message.text.toLowerCase();
let inferredType = null;
if (originalMsg.includes('journal')) inferredType = 'journal';
else if (originalMsg.includes('project')) inferredType = 'project';
else if (originalMsg.includes('snapshot')) inferredType = 'snapshot';
else if (originalMsg.includes('restart')) inferredType = 'restart';
else if (originalMsg.includes('instruction')) inferredType = 'instruction_pack';

// Determine the claimed artifact_id (prefer explicitly labeled)
const claimedId = artifactIdMatch ? artifactIdMatch[1] : (uuidMatches ? uuidMatches[0] : null);

// Determine type (prefer output, fall back to inferred)
const claimedType = typeMatch ? typeMatch[1] : (savedTypeMatch ? savedTypeMatch[1] : inferredType);

return {
  claimed_artifact_id: claimedId,
  claimed_type: claimedType,
  has_claim: !!(claimedId && claimedType),
  ai_output: output,
  original_message: $('Telegram_Trigger').item.json.message.text
};
